import React, { useEffect, useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';
import { useTheme } from '../hooks/useTheme';
import api from '../utils/api';

export default function Sidebar() {
  const { user, logout } = useAuth();
  const { theme, toggle } = useTheme();
  const navigate = useNavigate();
  const isStaff = user?.userType === 'user';
  const isDark = theme === 'dark';
  const [unreadCount, setUnreadCount] = useState(0);

  useEffect(() => {
    if (!user || isStaff) return;
    const fetchUnread = () => {
      api.get('/announcements/unread-count').then(r => setUnreadCount(r.data.count || 0)).catch(() => {});
    };
    fetchUnread();
    const id = setInterval(fetchUnread, 60000);
    return () => clearInterval(id);
  }, [user, isStaff]);

  const navItems = [
    { path:'/dashboard',        label:'Dashboard',        show:true },
    { path:'/books',            label:'Books',             show:true },
    { path:'/members',          label:'Members',           show:isStaff },
    { path:'/requests',         label:'Borrow Requests',   show:isStaff },
    { path:'/borrows',          label:'Borrows',           show:isStaff },
    { path:'/categories',       label:'Categories',        show:true },
    { path:'/announcements',    label:'Notifications',     show:true, badge: isStaff ? 0 : unreadCount },
    { path:'/create-assistant', label:'Add Assistant',     show:user?.role==='librarian' },
    { path:'/my-borrows',       label:'My Library',        show:!isStaff },
  ];

  const roleColor:any = { librarian:'#c9a84c', library_assistant:'#39ff8f', student:'#00e5ff', staff:'#a78bfa' };
  const roleLabel:any = { librarian:'Head Librarian', library_assistant:'Asst. Librarian', student:'Student', staff:'Staff Member' };
  const rc = roleColor[user?.role||''] || '#c9a84c';

  return (
    <>
      <style>{`
        .nav-lnk {
          display:flex; align-items:center; gap:10px;
          padding:10px 14px; border-radius:10px;
          font-size:13.5px; font-weight:500;
          color:var(--sidebar-text); text-decoration:none;
          margin-bottom:2px; transition:all .18s; position:relative;
          letter-spacing:.01em;
        }
        .nav-lnk::before {
          content:''; position:absolute; left:0; top:20%; bottom:20%;
          width:3px; background:var(--gold); border-radius:0 3px 3px 0;
          opacity:0; transform:scaleY(0); transition:all .2s;
        }
        .nav-lnk:hover {
          color:var(--sidebar-text-hover);
          background:rgba(124,92,255,0.08);
        }
        .nav-lnk.active {
          color:#fff !important;
          background: linear-gradient(90deg, rgba(201,168,76,0.18), rgba(201,168,76,0.06)) !important;
          font-weight:700 !important;
          border: 1px solid rgba(201,168,76,0.15) !important;
        }
        .nav-lnk.active::before { opacity:1; transform:scaleY(1); }

        [data-theme="dark"] .nav-lnk:hover {
          background: rgba(124,92,255,0.1);
          box-shadow: inset 0 0 20px rgba(124,92,255,0.05);
        }
        [data-theme="dark"] .nav-lnk.active {
          box-shadow: 0 0 20px rgba(201,168,76,0.1), inset 0 0 20px rgba(201,168,76,0.05) !important;
        }
        .so-btn:hover {
          color:#f87171 !important;
          background:rgba(239,68,68,0.08) !important;
          border-color:rgba(239,68,68,0.15) !important;
          box-shadow: 0 0 16px rgba(239,68,68,0.1) !important;
        }
        .theme-pill { transition: all .25s !important; }
        .theme-pill:hover { filter:brightness(1.15); transform:scale(1.02); }
      `}</style>

      <aside style={{ width:244, minHeight:'100vh', background:'var(--sidebar-bg)', borderRight:`1px solid var(--sidebar-border)`, display:'flex', flexDirection:'column', flexShrink:0, position:'relative', zIndex:10 }}>

        {/* Purple ambient glow top */}
        {isDark && <>
          <div style={{ position:'absolute', top:-40, left:-40, width:200, height:200, background:'radial-gradient(circle, rgba(124,92,255,0.12), transparent 70%)', pointerEvents:'none', zIndex:0 }}/>
          <div style={{ position:'absolute', bottom:-40, right:-20, width:160, height:160, background:'radial-gradient(circle, rgba(0,229,255,0.06), transparent 70%)', pointerEvents:'none', zIndex:0 }}/>
        </>}

        {/* Logo */}
        <div style={{ padding:'26px 20px 20px', borderBottom:`1px solid var(--sidebar-border)`, position:'relative', zIndex:1 }}>
          <div style={{ fontFamily:"'Playfair Display',serif", fontSize:22, fontWeight:700, color:'#fff', letterSpacing:'-0.3px', lineHeight:1 }}>
            LibraryMS
          </div>
          <div style={{ fontSize:9.5, color: isDark?'rgba(124,92,255,0.6)':'rgba(201,168,76,0.55)', letterSpacing:'2.5px', textTransform:'uppercase', marginTop:5, fontWeight:600 }}>
            BAUST · University Library
          </div>
          <div style={{ marginTop:14, height:1, background: isDark
            ? 'linear-gradient(90deg,rgba(124,92,255,0.5),rgba(201,168,76,0.4),transparent)'
            : 'linear-gradient(90deg,rgba(201,168,76,0.4),transparent)'
          }}/>
        </div>

        {/* Nav */}
        <nav style={{ flex:1, padding:'16px 10px', overflowY:'auto', position:'relative', zIndex:1 }}>
          <div style={{ fontSize:9.5, fontWeight:700, color:'var(--nav-section-color)', letterSpacing:'2.5px', textTransform:'uppercase', padding:'0 6px', marginBottom:10 }}>
            Navigation
          </div>
          {navItems.filter(i=>i.show).map(item=>(
            <NavLink key={item.path} to={item.path}
              className={({isActive})=>`nav-lnk${isActive?' active':''}`}
              style={{ justifyContent:'space-between' }}>
              <span>{item.label}</span>
              {(item.badge ?? 0) > 0 && (
                <span style={{ background:'#dc2626', color:'#fff', fontSize:10, fontWeight:700, padding:'2px 7px', borderRadius:99, lineHeight:1.4 }}>
                  {item.badge}
                </span>
              )}
            </NavLink>
          ))}
        </nav>

        {/* Theme toggle */}
        <div style={{ padding:'0 10px 10px', position:'relative', zIndex:1 }}>
          <button className="theme-pill" onClick={toggle}
            style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'space-between', padding:'10px 14px', borderRadius:12,
              background: isDark ? 'rgba(124,92,255,0.08)' : 'rgba(255,255,255,0.06)',
              border: `1px solid ${isDark?'rgba(124,92,255,0.15)':'rgba(255,255,255,0.1)'}`,
              cursor:'pointer', fontFamily:'inherit'
            }}>
            <div style={{ display:'flex', alignItems:'center', gap:8 }}>
              <span style={{ fontSize:14 }}>{isDark?'🌙':'☀️'}</span>
              <span style={{ fontSize:12.5, color: isDark?'rgba(200,190,255,0.5)':'rgba(255,255,255,0.5)', fontWeight:600 }}>
                {isDark?'Dark Mode':'Light Mode'}
              </span>
            </div>
            <div style={{ width:40, height:22, borderRadius:99,
              background: isDark ? 'linear-gradient(90deg,#7c5cff,#4f35cc)' : '#c9a84c',
              position:'relative', transition:'background .25s', flexShrink:0,
              boxShadow: isDark?'0 0 12px rgba(124,92,255,0.4)':'none'
            }}>
              <div style={{ position:'absolute', top:3, left:isDark?3:20, width:16, height:16, borderRadius:'50%', background:'#fff', transition:'left .25s', boxShadow:'0 1px 4px rgba(0,0,0,0.4)' }}/>
            </div>
          </button>
        </div>

        {/* User */}
        <div style={{ padding:'8px 10px 20px', borderTop:`1px solid var(--sidebar-border)`, position:'relative', zIndex:1 }}>
          <div style={{
            background: isDark ? 'rgba(255,255,255,0.03)' : 'rgba(255,255,255,0.05)',
            border: `1px solid ${isDark?'rgba(124,92,255,0.1)':'rgba(255,255,255,0.08)'}`,
            borderRadius:14, padding:'13px', marginBottom:8
          }}>
            <div style={{ display:'flex', alignItems:'center', gap:10, marginBottom:user?.member_id?9:0 }}>
              <div style={{ width:36, height:36, borderRadius:'50%',
                background:`linear-gradient(135deg,${rc},${rc}88)`,
                border:`2px solid ${rc}44`,
                display:'flex', alignItems:'center', justifyContent:'center',
                fontWeight:800, color:'#000', fontSize:15, flexShrink:0,
                boxShadow:`0 0 16px ${rc}50`
              }}>
                {user?.name?.charAt(0).toUpperCase()}
              </div>
              <div style={{ minWidth:0, flex:1 }}>
                <div style={{ fontSize:13, fontWeight:700, color:'#fff', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{user?.name}</div>
                <div style={{ fontSize:11, color:rc, marginTop:1, fontWeight:600 }}>{roleLabel[user?.role||'']||user?.role}</div>
              </div>
            </div>
            {user?.member_id && (
              <div style={{ background:'rgba(0,0,0,0.2)', borderRadius:7, padding:'4px 9px', display:'inline-flex', alignItems:'center', gap:5 }}>
                <span style={{ fontSize:9, color:'rgba(255,255,255,0.2)', fontWeight:700, letterSpacing:'1px', textTransform:'uppercase', fontFamily:"'Space Mono',monospace" }}>ID</span>
                <span style={{ fontSize:11, color:'rgba(255,255,255,0.45)', fontFamily:"'Space Mono',monospace", fontWeight:400 }}>{user.member_id}</span>
              </div>
            )}
          </div>
          <button className="so-btn"
            onClick={()=>{ logout(); navigate('/login'); }}
            style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'center', gap:8, padding:'9px', borderRadius:10, fontSize:12.5, fontWeight:600, color:'rgba(255,255,255,0.28)', background:'transparent', border:`1px solid rgba(255,255,255,0.06)`, cursor:'pointer', fontFamily:'inherit', transition:'all .18s' }}>
            ⎋ Sign Out
          </button>
        </div>
      </aside>
    </>
  );
}
